#!/usr/bin/perl
use strict;
use warnings;
use CGI qw(:standard);

my $cgi = new CGI;
my $log_dir = "/path/to/log/directory";
my $filename = $cgi->param('logfile');

print $cgi->header('text/plain');

if ($filename =~ /^([-\@\w.]+)$/) {
    $filename = $1;                     
} else {
    die "Bad filename";
}

open(FH, "<", "$log_dir/$filename") or die "Can't open $filename: $!";
while(<FH>) {
    print $_;
}
close FH;